while time.time() - start_time < timeout:
    # Read output from both stdout and stderr
    for stream in [process.stdout, process.stderr]:
        line = stream.readline()
        if line:
            print(f"[PROCESS]: {line.strip()}")
            if "FATAL: Application detected continuous mock data usage" in line:
                fatal_log_found = True
                break

    if fatal_log_found:
        break

    if process.poll() is not None:
        break
    time.sleep(0.1)

